       const addStyles = () => {
        var css = ` 

    .embed-design-container {
        position: relative;
        height: 100%;
        min-height: 500px;
        width: 100%;
        font-family:   "Open Sans", sans-serif;
    }

    .embed-canvas-container p {
        margin: 0;
        padding: 0;
    }

    #embedded-design-940eefad-a902-45ef-a2d0-a2463b05a8dc .embed-canvas-container {
        height: 100%;
        width: 100%;
        background-color: "inheirt";
    }
   #embedded-design-940eefad-a902-45ef-a2d0-a2463b05a8dc .water-mark{
        background: "transparent";
        padding: 0.5rem;
        color : inherit !important;
        font-size: 1.5rem !important;
        border: none;
        cursor: pointer;
        display: flex !important;
        align-items: center;
        gap: 0.5rem;
        font-family:   "Open Sans", sans-serif !important;
        text-decoration: none !important;
        outline: none !important;
    }

    #embedded-design-940eefad-a902-45ef-a2d0-a2463b05a8dc .toolbar {

        pointer-events: auto ;
        padding: 0.5rem;
        cursor: pointer;
        color : inherit;
        display: flex;
        gap: 0.5rem;
        justify-content: space-between;
        align-items: center;
        font-size: 1.25rem;
   }
     `,
        head = document.head || document.getElementsByTagName('head')[0],
        style = document.createElement('style');

        head.appendChild(style);

        style.type = 'text/css';
        if (style.styleSheet){
          // This is required for IE8 and below.
          style.styleSheet.cssText = css;
        } else {
          style.appendChild(document.createTextNode(css));
        }
      }

